insert into knowledge_nodes (id, project_id, node_key, label, category, sub_label, facts, talkpoint, description, sort_order) values
  ('ee1c1d2d-a794-563b-8490-8dff9957627c','00000000-0000-0000-0000-00000000b009','diamond','Diamond Sky','project','Căn hộ cao tầng đầu tiên · Vạn Phúc City 198ha','[{"key":"Tên dự án","value":"Diamond Sky (tổ hợp căn hộ + officetel/khách sạn + TMDV)"},{"key":"Vị trí","value":"375 Quốc lộ 13, P. Hiệp Bình Phước, TP. Thủ Đức · trong KĐT Vạn Phúc City"},{"key":"Chủ đầu tư","value":"Van Phuc Group (Tập đoàn Vạn Phúc / Đại Phúc)"},{"key":"Cấu trúc","value":"Block A (căn hộ, 21 tầng) + Block B (khách sạn/officetel/TMDV, 18 tầng) · 2 tầng hầm"},{"key":"Số căn (cần xác minh)","value":"~296–306 căn + 7 căn TMDV/shophouse"},{"key":"View","value":"3 hướng sông Sài Gòn · trước mặt hồ Đại Nhật + quảng trường nhạc nước"},{"key":"Pháp lý","value":"Block A: sở hữu lâu dài (người Việt)"},{"key":"Khởi công hầm","value":"08–09/01/2026"},{"key":"Bàn giao","value":"Dự kiến cuối 2027 / 2028 (hoàn thiện cao cấp)"},{"key":"Giá (chưa chính thức)","value":"Dự kiến ~120–150 triệu/m²"}]'::jsonb,null,'Định danh dự án Câu chuyện đầu tư trong 3 dòng: căn hộ cao tầng đầu tiên trong đại đô thị Vạn Phúc City 198ha đã hình thành — "điểm vào" hệ sinh thái ven sông cho khách không mua thấp tầng. Lợi thế là vị trí kim cương view sông/hồ + hệ tiện ích đại đô thị hiện hữu + QL13 đang mở rộng; lưu ý giá còn là dự kiến và một số tiện ích lớn chưa hoàn tất.',0),
  ('9674ee70-b2b2-5c8b-81b5-371d08f4d148','00000000-0000-0000-0000-00000000b009','tq-vitri','Vị trí QL13 ven sông','project','Hiệp Bình Phước · 3 hướng view sông SG','[]'::jsonb,null,'Tọa độ "kim cương" Diamond Sky nằm ở trung tâm Vạn Phúc City, mặt tiền Quốc lộ 13 ("đường tơ lụa" nối TP.HCM – Bình Dương – Bình Phước), P. Hiệp Bình Phước, TP. Thủ Đức. Sở hữu 3 hướng view sông Sài Gòn, trước mặt là hồ Đại Nhật + quảng trường nhạc nước. Kết nối • QL13 → Phạm Văn Đồng → sân bay Tân Sơn Nhất & trung tâm Q1/Q3 ~10 phút • QL13 → QL1A → Đồng Nai, Bình Dương, Long An • Cận trục chính nội khu 52m + đường Nguyễn Thị Nhung (lộ giới 35m)',1),
  ('4d88e78c-9ac0-53a6-bd3a-f67d18c06972','00000000-0000-0000-0000-00000000b009','tq-quymo','Quy mô & số liệu','project','Số liệu mâu thuẫn giữa các nguồn','[]'::jsonb,null,'Khác biệt chủ yếu ở tổng diện tích và số căn (296 vs 306). Cấu trúc nhất quán: 2 block (A căn hộ + B khách sạn/officetel/TMDV) + 2 hầm.',2),
  ('3def149e-7f9d-5ca3-b79e-3fd8a70afe0b','00000000-0000-0000-0000-00000000b009','tq-mauthuan','Cảnh báo mâu thuẫn số liệu','project','296 vs 306 căn · 1,8ha vs Block A+B','[]'::jsonb,null,'Dự án mới khởi công phần hầm (1/2026), chưa có bảng hàng chính thức — nhiều con số đang lưu hành:',3),
  ('d07ab02e-68b1-5628-ae6e-671f9d82a915','00000000-0000-0000-0000-00000000b009','tq-blocks','Cấu trúc Block A & B','project','Căn hộ (21T) + Khách sạn/officetel (18T)','[]'::jsonb,null,'Mô hình phức hợp residence + commercial + officetel/hotel: Block A để ở, Block B khai thác thương mại – lưu trú – văn phòng, bổ trợ TTTM Vạn Phúc Center.',4),
  ('ff5d3e98-c787-54e6-afc5-16dc71d6be9d','00000000-0000-0000-0000-00000000b009','tq-thietke','Thiết kế & tầm nhìn','project','Ý tưởng hoàng gia Châu Âu · panorama sông','[]'::jsonb,null,'Theo nguồn thị trường, kiến trúc Diamond Sky lấy ý tưởng hoàng gia Châu Âu, thiết kế hiện đại với tầm nhìn panorama hướng sông Sài Gòn, hồ Đại Nhật và trung tâm thành phố (view Landmark 81, sân bay).',5),
  ('da3307bf-6782-5424-84bb-6dc05f5a1a74','00000000-0000-0000-0000-00000000b009','tq-dinhvi','Định vị "điểm vào" đại đô thị','project','Cao tầng đầu tiên trong Vạn Phúc City','[]'::jsonb,null,'Diamond Sky là sản phẩm cao tầng đầu tiên trong Vạn Phúc City — tạo "entry point" cho khách muốn vào hệ sinh thái Vạn Phúc nhưng không mua nhà phố/biệt thự thấp tầng (giá trị lớn hơn nhiều).',6),
  ('512fe659-1ddd-5158-bbb0-e2d8d624e24f','00000000-0000-0000-0000-00000000b009','cdt-vpg','Van Phuc Group (Đại Phúc)','developer','~26–30 năm BĐS · pháp lý minh bạch','[{"key":"Thế mạnh","value":"Năng lực phát triển đại đô thị (không chỉ một tòa nhà)"},{"key":"Pháp lý","value":"Được nhấn mạnh \"minh bạch\", sổ hồng các phân khu thấp tầng"},{"key":"Dự án lõi","value":"Vạn Phúc City 198ha (vốn đầu tư ~3 tỷ USD)"}]'::jsonb,null,'Tập đoàn Vạn Phúc (Van Phuc Group / Đại Phúc) là chủ đầu tư gắn liền với KĐT Vạn Phúc City, có ~26–30 năm kinh nghiệm phát triển bất động sản, định vị phân khúc cao cấp. Điểm mạnh khi tư vấn: Diamond Sky do chính chủ đầu tư đại đô thị phát triển — cộng hưởng thương hiệu, tiện ích và cộng đồng cư dân Vạn Phúc.',7),
  ('60b6637a-087d-53bc-8ecf-b8602e24a570','00000000-0000-0000-0000-00000000b009','cdt-vpcity','Vạn Phúc City 198ha','developer','Bán đảo ven sông · 3 tỷ USD','[{"key":"Quy mô","value":"198 ha (1.980.000 m²)"},{"key":"Vốn đầu tư","value":"~3 tỷ USD"},{"key":"Vị thế","value":"1 trong 3 bán đảo đẹp bên sông SG · 3 mặt giáp sông (~3,4 km)"},{"key":"Quy hoạch dân số","value":"~45.000 cư dân"}]'::jsonb,null,'Đại đô thị ven sông quy mô lớn bậc nhất khu Đông, gần giao lộ QL13 × Phạm Văn Đồng, cách sân bay Tân Sơn Nhất ~10 phút. Diamond Sky là mảnh ghép cao tầng trong tổng thể này.',8),
  ('c48106ac-5bb6-5392-97e6-b14bc6af04a7','00000000-0000-0000-0000-00000000b009','cdt-quyhoach','Quy hoạch xanh','developer','50% xanh + mặt nước · MĐXD ~40%','[]'::jsonb,null,'• 50% diện tích 198ha dành cho không gian xanh và mặt nước (công viên, kênh, hồ). • Mật độ xây dựng chỉ ~40%; 80% công trình là nhà ở thấp tầng (nhà phố, biệt thự). • Căn hộ cao tầng được quy hoạch tập trung quanh hồ trung tâm Đại Nhật — nơi Diamond Sky tọa lạc.',9),
  ('6dfe98bf-ded9-5dcc-85e3-602f8727534b','00000000-0000-0000-0000-00000000b009','cdt-phankhu','Các phân khu Vạn Phúc','developer','Vạn Phúc 1 · Đông Nam · Sunlake · Jardin · Royal','[]'::jsonb,null,'Hệ phân khu đa dạng (thấp tầng chủ đạo) đã tạo cộng đồng & tiện ích — nền cho sản phẩm cao tầng Diamond Sky kế thừa.',10),
  ('157c9e2f-d6f2-5e4a-8a28-4b5a8afae450','00000000-0000-0000-0000-00000000b009','cdt-hientrang','Hiện trạng lấp đầy','developer','~10.000 cư dân · 500+ thương hiệu','[]'::jsonb,null,'Vạn Phúc City đã hình thành cộng đồng thực: ~10.000 cư dân và hơn 500 thương hiệu kinh doanh; là nơi đặt trụ sở của nhiều doanh nghiệp, thu hút chuyên gia nước ngoài & nhân sự cấp cao.',11),
  ('812a58f2-11ca-5a5a-9847-c39f1cd3251b','00000000-0000-0000-0000-00000000b009','cdt-track','Track record & lưu ý cao tầng','developer','Mạnh thấp tầng · cao tầng là sản phẩm mới','[]'::jsonb,null,'Van Phuc Group có lịch sử bàn giao tốt ở phân khúc thấp tầng (nhà phố, biệt thự, shophouse) + sổ hồng — bảo chứng năng lực phát triển đại đô thị.',12),
  ('76ce7d8d-50c2-5cf4-b6fa-2a958a71c501','00000000-0000-0000-0000-00000000b009','pl-vpcity','Pháp lý Vạn Phúc City','legal','Minh bạch · sổ hồng phân khu thấp tầng','[]'::jsonb,null,'KĐT Vạn Phúc City được quảng bá pháp lý minh bạch; nhiều phân khu thấp tầng (nhà phố, biệt thự, shophouse) đã bàn giao + cấp sổ hồng cho cư dân — bảo chứng về nền pháp lý tổng thể của đại đô thị.',13),
  ('58ddcef6-02a1-5ba4-a5f0-e928550aa381','00000000-0000-0000-0000-00000000b009','pl-hientrang','Hiện trạng pháp lý bán hàng','legal','Khởi công hầm 1/2026 · xác minh đủ ĐK bán','[]'::jsonb,null,'Diamond Sky mới khởi công phần hầm 08–09/01/2026, đang nhận booking (giữ chỗ ~100 triệu/căn). Ở giai đoạn sớm này cần xác minh dự án đã có văn bản đủ điều kiện bán nhà ở hình thành trong tương lai của Sở Xây dựng hay chưa.',14),
  ('bc29be7d-e6ef-58e8-9c25-7d1497ab8788','00000000-0000-0000-0000-00000000b009','pl-sohuu','Sở hữu Block A','legal','Căn hộ — sở hữu lâu dài (người Việt)','[]'::jsonb,null,'Block A (căn hộ ở): sở hữu lâu dài cho người Việt Nam (room người nước ngoài tối đa 30%/tòa theo luật). Đây là lợi thế giữ giá & thanh khoản thứ cấp dài hạn.',15),
  ('df8df0b8-03ed-51b7-a979-779a611d0008','00000000-0000-0000-0000-00000000b009','pl-blockB','Pháp lý Block B','legal','Officetel/khách sạn/TMDV — thời hạn','[]'::jsonb,null,'Block B gồm văn phòng/officetel, khách sạn, TMDV, rạp phim. Các sản phẩm này thường sở hữu có thời hạn (theo thời hạn đất dự án), không phải lâu dài như căn hộ ở; pháp lý officetel/condotel ở VN còn nhiều điểm cần lưu ý.',16),
  ('ee2c89f6-0a39-5199-8c26-621effa77bd8','00000000-0000-0000-0000-00000000b009','pl-checklist','Checklist trước cọc','legal','6 bước — chú ý dự án mới khởi công','[]'::jsonb,null,'• 1. Quyết định chủ trương đầu tư + quy hoạch 1/500 của dự án Diamond Sky. • 2. Giấy phép xây dựng (đã khởi công hầm 1/2026). • 3. Văn bản đủ điều kiện bán nhà ở hình thành trong tương lai — nếu CHƯA có, chỉ "giữ chỗ" hoàn lại. • 4. Bảng giá chính thức + xác định rõ mua Block A (lâu dài) hay Block B (thời hạn). • 5. Chứng thư bảo lãnh ngân hàng cho nghĩa vụ bàn giao (đúng mã căn). • 6. Tiến độ thanh toán theo trần luật: ≤70% trước bàn giao, ≤95% trước khi cấp sổ.',17),
  ('624dfd9d-3967-529f-b47e-e4ab06e1cfdd','00000000-0000-0000-0000-00000000b009','pk-blockA','Block A — Căn hộ','masterplan','7.538 m² · 21 tầng · ~306 căn','[{"key":"Diện tích sàn","value":"~7.538 m²"},{"key":"Chiều cao","value":"21 tầng"},{"key":"Bố trí","value":"T1–2 shophouse · T3 tiện ích/hồ bơi · T4–21 căn hộ"},{"key":"Số căn","value":"~306 (GĐ1) — cần đối chiếu (vanphuc.city nêu ~296)"}]'::jsonb,null,'Khối ở chính, view sông Sài Gòn & hồ Đại Nhật. Tầng tiện ích (T3) + khối đế shophouse tạo mô hình ở khép kín.',18),
  ('e8da8398-6f19-5e48-9b89-06ed962a1502','00000000-0000-0000-0000-00000000b009','pk-blockB','Block B — Khách sạn/Officetel','masterplan','10.043 m² · 18 tầng · TMDV','[{"key":"Diện tích sàn","value":"~10.043 m²"},{"key":"Chiều cao","value":"18 tầng"},{"key":"Bố trí","value":"T1–2 TM · T3 TM + rạp phim · T4 nhà hàng · T5–17 văn phòng/officetel · T18 kỹ thuật"}]'::jsonb,null,'Khối khai thác thương mại – lưu trú – văn phòng, bổ trợ TTTM Vạn Phúc Center, phục vụ cộng đồng cư dân + doanh nghiệp Vạn Phúc.',19),
  ('2825cc0c-b767-5c74-9d20-f01ecf89ec70','00000000-0000-0000-0000-00000000b009','pk-loaican','Loại căn & diện tích','masterplan','Số lượng giới hạn · cần bảng hàng','[]'::jsonb,null,'CĐT định vị "số lượng giới hạn". Chi tiết cơ cấu loại căn (1PN/2PN/3PN) & diện tích từng loại của Diamond Sky chưa được công bố đầy đủ tại thời điểm khởi công.',20),
  ('616b78c8-7890-5071-afb3-33939e15338e','00000000-0000-0000-0000-00000000b009','pk-bangiao','Tiêu chuẩn bàn giao','masterplan','Hoàn thiện chuẩn cao cấp (theo CĐT)','[]'::jsonb,null,'Theo công bố, Diamond Sky bàn giao hoàn thiện chuẩn cao cấp. Chi tiết bộ tiêu chuẩn (thương hiệu thiết bị, mức nội thất) chưa công bố cụ thể.',21),
  ('f6a42d36-58d0-5e2b-8ecd-5a5f9cb66ac5','00000000-0000-0000-0000-00000000b009','pk-tiendo','Tiến độ & bàn giao','masterplan','Khởi công hầm 1/2026 → bàn giao 2027/2028','[]'::jsonb,null,null,22),
  ('c377baa0-5738-5417-a1f2-46561f4e1968','00000000-0000-0000-0000-00000000b009','ti-hodainhat','Hồ Đại Nhật & nhạc nước','amenity','Hồ 16–21ha · quảng trường Diamond','[]'::jsonb,null,'Ngay trước mặt Diamond Sky là hồ trung tâm Đại Nhật (~16–21ha tùy nguồn) và quảng trường Diamond với công trình nhạc nước biểu diễn mỗi cuối tuần — điểm nhấn cảnh quan & giải trí của đại đô thị.',23),
  ('b12f7c3d-520f-5665-8514-1e075904f11c','00000000-0000-0000-0000-00000000b009','ti-song','Sông Sài Gòn & công viên','amenity','3,4km sông · The Long Park 11ha','[]'::jsonb,null,'Vạn Phúc City có ~3,4 km sông Sài Gòn bao quanh (3 mặt), công viên The Long Park ~11ha, kênh Sông Trăng ~2km + công viên ven kênh ~5ha. Diamond Sky thừa hưởng cảnh quan sông – hồ – kênh đặc trưng.',24),
  ('02b1bdea-c330-50dc-a65e-cbdd65656ebe','00000000-0000-0000-0000-00000000b009','ti-oceanworld','Công viên Ocean World 16ha','amenity','Theo quy hoạch · CHƯA triển khai','[]'::jsonb,null,'Quy hoạch có công viên giải trí quốc tế Ocean World quy mô ~16ha — tiện ích biểu tượng dự kiến của Vạn Phúc City.',25),
  ('a167f1e2-b3a9-5c57-8ee8-49b1afeca7b9','00000000-0000-0000-0000-00000000b009','ti-vanphuccenter','TTTM Vạn Phúc Center','amenity','Trung tâm thương mại · CHƯA xong','[]'::jsonb,null,'Trung tâm thương mại Vạn Phúc Center được quy hoạch là hạt nhân mua sắm – giải trí của đại đô thị, gắn với khối TMDV Block B của Diamond Sky.',26),
  ('f2f9f568-8573-5b2b-8d80-a2a042d19f6a','00000000-0000-0000-0000-00000000b009','ti-noikhu','Tiện ích nội khu Diamond Sky','amenity','Hồ bơi 4 mùa · gym · yoga · BBQ','[]'::jsonb,null,'Tiện ích nội khu (tầng đế/T3): hồ bơi 4 mùa, hồ bơi vô cực, hồ bơi trẻ em, phòng gym, yoga, phòng tập nhảy, phòng sinh hoạt đa năng, không gian tổ chức tiệc, khu BBQ ngoài trời, sân bóng rổ, công viên sân vườn.',27),
  ('e8007bc8-32e3-57c8-a28c-dfd805300736','00000000-0000-0000-0000-00000000b009','ti-royal','Cộng đồng & phố thương mại','amenity','500+ thương hiệu · phố đi bộ Royal','[]'::jsonb,null,'Vạn Phúc City đã có cộng đồng ~10.000 cư dân + 500+ thương hiệu kinh doanh, phố đi bộ Châu Âu Royal, chuỗi shophouse — tạo nhịp sống thương mại – dịch vụ sôi động quanh Diamond Sky.',28),
  ('859d8001-1fb7-5ddb-b0e2-611da8c8afbc','00000000-0000-0000-0000-00000000b009','ht-ql13','QL13 mở rộng','infra','60m · 10 làn · >21.000 tỷ · 2026–2028','[]'::jsonb,null,'Dự án nâng cấp & mở rộng Quốc lộ 13 lên 60m, 10 làn xe, tổng vốn >21.000 tỷ đồng, dự kiến khởi công Q2/2026, hoàn thành 2028. Khi xong, QL13 thành "đại lộ đô thị" xóa điểm nghẽn cửa ngõ Đông Bắc.',29),
  ('5b140555-0550-539b-a357-580b0eb9785a','00000000-0000-0000-0000-00000000b009','ht-pvd','Phạm Văn Đồng & sân bay','infra','~10 phút tới Q1/Q3 & Tân Sơn Nhất','[]'::jsonb,null,'QL13 → Đại lộ Phạm Văn Đồng (12 làn) → sân bay Tân Sơn Nhất & trung tâm Q1/Q3 chỉ ~10 phút. Phạm Văn Đồng là cửa ngõ huyết mạch kết nối khu Đông Bắc với phần còn lại của TP.HCM.',30),
  ('8cda9b8b-af28-5e6c-9e24-c89028e62715','00000000-0000-0000-0000-00000000b009','ht-metro','Metro 3B & đường sắt','infra','Metro 3B · đường sắt Bắc–Nam','[]'::jsonb,null,'Theo quy hoạch, khu vực hưởng lợi từ tuyến Metro số 3B và đường sắt Bắc–Nam đi qua/gần khu vực — bổ sung lựa chọn giao thông công cộng dài hạn.',31),
  ('1212dc1c-a66b-5e46-8322-47daad1902e4','00000000-0000-0000-0000-00000000b009','ht-vanhdai','Vành đai 2 & đa phương thức','infra','VĐ2 · QL1A · đường thủy','[]'::jsonb,null,'Mạng kết nối đa phương thức: Vành đai 2, QL1A, tuyến đường thủy sông Sài Gòn (tiềm năng bến du thuyền/giao thông thủy), kết nối Đồng Nai – Bình Dương – Long An.',32),
  ('fd9e0da3-c347-5ddb-8ffc-1ac62e139c82','00000000-0000-0000-0000-00000000b009','ht-noikhu','Hạ tầng nội khu','infra','Trục chính 52m · Nguyễn Thị Nhung 35m','[]'::jsonb,null,'Diamond Sky cận trục đường chính 52m chạy dọc Vạn Phúc City và đường Nguyễn Thị Nhung (lộ giới 35m) — trục huyết mạch nội khu. Hạ tầng nội khu đại đô thị đã đầu tư đồng bộ.',33),
  ('21ed1d4f-b835-5532-a2b1-010885efaccd','00000000-0000-0000-0000-00000000b009','ht-tacdong','"Điểm rơi" hạ tầng','infra','QL13 hoàn thành 2028 cộng hưởng','[]'::jsonb,null,'Các lớp giá trị quanh Diamond Sky: • Hệ sinh thái Vạn Phúc 198ha + cộng đồng đã hiện hữu (de-risk một phần) • Kết nối Phạm Văn Đồng → Q1/sân bay ~10 phút đã hiện hữu • QL13 mở rộng (Q2/2026 → 2028) — chất xúc tác trung hạn • Metro 3B, Vành đai 2, đường thủy — dài hạn',34),
  ('542eeb1c-467a-54ca-acee-5da1011a33dc','00000000-0000-0000-0000-00000000b009','cs-gia','Giá bán','policy','Dự kiến 99–150 tr/m² · chưa chính thức','[]'::jsonb,null,'Giá Diamond Sky chưa có bảng giá chính thức (đang nhận booking, mở bán GĐ1). Các mức dự kiến/rumor đang lưu hành rất khác nhau: Tổng giá căn (giả định ~70 m²) ước ~8,5–10,5 tỷ tùy đơn giá & loại căn.',35),
  ('df03398e-bb12-56b6-a767-b2ad93e0e19d','00000000-0000-0000-0000-00000000b009','cs-benchmark','So sánh giá khu vực','policy','Thủ Đức 35–60 · Diamond 120–150 · Thủ Thiêm 200–350','[]'::jsonb,null,'Luận điểm bán (chodat): "Thủ Thiêm đã 200–350 tr/m², Diamond Sky ~125 tr/m² còn biên độ tăng trưởng lớn khi QL13 hoàn thiện."',36),
  ('f5c4bf13-f572-57c5-8e72-e9acb60bc94e','00000000-0000-0000-0000-00000000b009','cs-thanhtoan','Chính sách thanh toán','policy','Vạn Phúc: 30% kéo dài 2–3 năm','[]'::jsonb,null,'Chính sách điển hình của Van Phuc Group: thanh toán ~30% kéo dài 2–3 năm, hỗ trợ vay ngân hàng, trả góp ưu đãi. Diamond Sky đang nhận booking giữ chỗ ~100 triệu/căn.',37),
  ('86c91f37-a211-5cce-aa0e-00eb7d3404f9','00000000-0000-0000-0000-00000000b009','cs-yield','Tỷ suất cho thuê','policy','Modest ~2–3% · thiên capital gain','[]'::jsonb,null,'Tham chiếu cho thuê khu vực: căn 2PN ~75–85 m² ở Thủ Đức (Opal Boulevard) cho thuê ~7,5–13 triệu/tháng trên giá vốn ~35 tr/m² → yield ~3–5%. Ở mức giá Diamond Sky (~120–150 tr/m²), yield sẽ thấp hơn (~2–3%) trừ khi giá thuê cao vượt trội nhờ vị thế ven sông.',38),
  ('7835ef14-f948-5e6c-9cff-20a4c0c9abac','00000000-0000-0000-0000-00000000b009','cs-thitruong','Bối cảnh thị trường khu Đông','policy','QL13 là driver · khan cung cao cấp ven sông','[]'::jsonb,null,'• Khu Đông TP.HCM tiếp tục dẫn dắt nguồn cung & giá; sản phẩm ven sông cao cấp khan hiếm. • QL13 mở rộng (>21.000 tỷ) là động lực hạ tầng lớn cho trục Hiệp Bình – Bình Triệu – Bình Dương. • Mặt bằng giá Thủ Thiêm 200–350 tr/m² tạo "trần tham chiếu" để định vị các dự án ven sông khác.',39),
  ('054c0e60-8b4f-5293-b95b-bba80e03f27f','00000000-0000-0000-0000-00000000b009','tt-opal','Opal Boulevard (Đất Xanh)','comparable','Phạm Văn Đồng · ~35 tr/m² · đã bàn giao','[{"key":"CĐT","value":"Đất Xanh Group"},{"key":"Vị trí","value":"Kha Vạn Cân, song song Phạm Văn Đồng (giáp Thủ Đức)"},{"key":"Quy mô","value":"14.757 m² · 2 block 35T · 1.446 căn + 22 shophouse"},{"key":"Giá","value":"từ ~35 triệu/m² (đã bàn giao 5/2021)"},{"key":"Cho thuê 2PN","value":"~7,5–13 triệu/tháng"}]'::jsonb,null,'Đại diện mặt bằng căn hộ hiện hữu khu Phạm Văn Đồng/QL13. So với Diamond Sky: Opal giá thấp hơn nhiều (~35 vs 120–150), đã bàn giao, gần GigaMall/Vincom; Diamond Sky định vị cao cấp hơn hẳn nhờ hệ sinh thái Vạn Phúc + ven sông.',40),
  ('95ab26bd-6da0-5cf8-9588-797ec0e6a548','00000000-0000-0000-0000-00000000b009','tt-kingcrown','King Crown City','comparable','Bamboo Capital · MT Phạm Văn Đồng','[]'::jsonb,null,'King Crown City (Bamboo Capital, tổng thầu dự kiến Central Cons) — tổ hợp cao cấp mặt tiền Phạm Văn Đồng, Thủ Đức. Cùng trục cửa ngõ, hướng phân khúc cao cấp.',41),
  ('8c4417c2-4e9d-5965-b11d-d3cbaec5c843','00000000-0000-0000-0000-00000000b009','tt-thuthiem','Thủ Thiêm (trần giá)','comparable','Empire/Metropole/Sala 200–350+','[]'::jsonb,null,'Lõi cao cấp khu Đông là Thủ Thiêm: Empire City (~210–500), Metropole (~170–440), Sala (~200–260). Đây là "trần giá" khu Đông, cao hơn Diamond Sky đáng kể.',42),
  ('431041ee-fa29-5fe6-973f-74bb876640f5','00000000-0000-0000-0000-00000000b009','tt-noibo','Diamond Valley / Boulevard','comparable','Cao tầng khác trong Vạn Phúc','[]'::jsonb,null,'Trong Vạn Phúc City còn các sản phẩm cao tầng khác: Diamond Valley, Diamond Boulevard (tổ hợp căn hộ + officetel + TTTM ven hồ Đại Nhật). Cùng CĐT, cùng hệ tiện ích.',43),
  ('bd625e75-15e9-568b-b94b-858cd5465ddb','00000000-0000-0000-0000-00000000b009','tt-dinhvi','Định vị & SWOT','comparable','Lợi thế / điểm yếu Diamond Sky','[]'::jsonb,null,'Lợi thế (Strengths) • Trong đại đô thị Vạn Phúc 198ha đã hình thành (cộng đồng, tiện ích, thương mại hiện hữu) • Vị trí kim cương ven hồ Đại Nhật, 3 hướng view sông SG, mặt tiền QL13 • Kết nối Phạm Văn Đồng → Q1/sân bay ~10 phút; QL13 sắp mở rộng • Giá mềm hơn Thủ Thiêm; CĐT pháp lý minh bạch, thanh toán giãn Điểm yếu / Thách thức (Weaknesses) • Giá dự kiến cao gấp 2–3 lần mặt bằng căn hộ Thủ Đức/QL13 hiện hữu • Giá & số liệu quy mô chưa chính thức (mâu thuẫn nguồn) • Cao tầng là dòng sản phẩm mới của CĐT; một số tiện ích lớn (Ocean World, Van Phuc Center) chưa xong • Yield thấp; Block B (officetel) pháp lý cần lưu ý; QL13 thi công gây bất tiện ngắn hạn',44),
  ('9318536f-d964-5550-8a5d-b1a04413836d','00000000-0000-0000-0000-00000000b009','tt-premium','Lưu ý "phần bù giá"','comparable','Premium lớn vs hàng xóm Thủ Đức','[]'::jsonb,null,'Điểm cần tỉnh táo nhất: Diamond Sky (~120–150 tr/m²) định giá cao hơn 2–3 lần các dự án căn hộ lân cận đã bàn giao (Opal Boulevard ~35, mặt bằng Thủ Đức ~40–60).',45),
  ('6602435e-0c41-5215-86e2-b695730b0659','00000000-0000-0000-0000-00000000b009','dt-thesis','Luận điểm đầu tư','finance','4 trụ cột — hệ sinh thái + ven sông + QL13','[]'::jsonb,null,'1 · Hệ sinh thái 198ha hiện hữu Cao tầng đầu tiên trong đại đô thị đã có cộng đồng (~10.000 cư dân), tiện ích, thương mại — "vào ở là có nhịp sống". 2 · Vị trí kim cương ven sông/hồ 3 hướng view sông SG + ven hồ Đại Nhật + nhạc nước — sản phẩm ven nước cao cấp khan hiếm. 3 · Chất xúc tác QL13 QL13 mở rộng 60m/10 làn (>21.000 tỷ, 2026–2028) nâng kết nối & giá trị cửa ngõ Đông Bắc. 4 · Phần bù vị trí & headroom vs Thủ Thiêm Giá mềm hơn Thủ Thiêm (200–350); CĐT pháp lý minh bạch, thanh toán giãn 30%.',46),
  ('fccb96b8-b8eb-563b-9ddc-6569228df35f','00000000-0000-0000-0000-00000000b009','dt-dongtien','Dòng tiền (mô phỏng)','finance','Vốn lớn · thanh toán giãn · yield thấp','[]'::jsonb,null,'Ví dụ căn 2PN ~70 m² × ~130 tr/m² ≈ 9,1 tỷ (ước lượng): Đặc điểm: thanh toán giãn 30% → vốn ban đầu vừa phải; nhưng phần còn lại khi nhận nhà lớn. Yield ~2–3% không đủ bù lãi vay (~9–10%) → lợi nhuận trông vào tăng giá vốn.',47),
  ('32c9d5d9-8ca8-5731-bd65-b0f29436407b','00000000-0000-0000-0000-00000000b009','dt-ruiro','Bản đồ rủi ro','finance','Giá rumor · premium · tiện ích chưa xong','[]'::jsonb,null,null,48),
  ('89c00024-e48d-549e-8b5e-8e5ecf1914cc','00000000-0000-0000-0000-00000000b009','dt-khuyennghi','Khuyến nghị theo mục tiêu','finance','Ai nên mua — và mua thế nào','[]'::jsonb,null,null,49),
  ('69ca6560-7eae-505f-9d47-d1c3d8172915','00000000-0000-0000-0000-00000000b009','dt-trigger','Tín hiệu Mua / Thận trọng','finance','Benchmark cập nhật quyết định','[]'::jsonb,null,'Tín hiệu MUA mạnh hơn • CĐT công bố bảng giá chính thức hợp lý + văn bản đủ điều kiện bán • Làm rõ số căn/diện tích & tiêu chuẩn bàn giao cao cấp • QL13 mở rộng khởi công Q2/2026 & bám tiến độ 2028 • Ocean World / Van Phuc Center khởi động xây dựng (tiện ích hiện thực hóa) Tín hiệu THẬN TRỌNG • Giá mở bán vượt xa khả năng hấp thụ của thị trường khu vực • QL13 hoặc tiện ích lớn chậm tiến độ kéo dài • Tiến độ/chất lượng bàn giao tháp cao tầng đầu tiên có vấn đề • Pháp lý bán hàng/HĐMB chưa rõ tại thời điểm mở bán',50),
  ('1d10a50f-f607-5bd2-bfbb-3d14d0463e69','00000000-0000-0000-0000-00000000b009','dt-kh','Chân dung khách mua','finance','Cư dân Vạn Phúc · chuyên gia · NĐT ven sông','[]'::jsonb,null,'Tệp khách Diamond Sky: • Khách muốn vào hệ sinh thái Vạn Phúc nhưng không mua thấp tầng (giá lớn hơn) — "điểm vào" căn hộ. • Gia đình trẻ/cư dân hiện hữu Vạn Phúc yêu môi trường ven sông, cộng đồng sẵn có. • Chuyên gia/nhân sự cấp cao làm việc tại doanh nghiệp trong Vạn Phúc (nguồn thuê). • Nhà đầu tư tích sản kỳ vọng tăng giá theo QL13 + đại đô thị (không phụ thuộc dòng thuê).',51);
